// Extract and normalize caller info from OpenPhone webhook
const input = $input.first().json;

// Only process missed inbound calls
if (input.direction !== 'inbound' || input.status !== 'missed') {
  return [{ json: { skip: true, reason: 'Not a missed inbound call' } }];
}

// Normalize phone to E.164
let phone = input.from || '';
if (phone && !phone.startsWith('+')) {
  phone = '+1' + phone.replace(/\D/g, '');
}

return [{
  json: {
    skip: false,
    caller: {
      phone: phone,
      name: input.contact?.name || 'Unknown Caller',
      existing_client: input.contact?.existing_client || false
    },
    call: {
      timestamp: input.timestamp,
      to: input.to,
      duration: input.duration,
      has_voicemail: input.voicemail || false
    },
    firm: 'Greenfield & Associates'
  }
}];

// Parse AI response and prepare follow-up data
const callerData = $('Extract Caller Info').first().json;
const aiResponse = $input.first().json;

let classification;
try {
  const content = aiResponse.choices?.[0]?.message?.content || '{}';
  classification = JSON.parse(content);
} catch (e) {
  classification = { intent: 'unknown', confidence: 0, suggested_response: 'We missed your call at Greenfield & Associates. How can we help?', priority: 'medium' };
}

return [{
  json: {
    ...callerData,
    ai_classification: classification,
    is_potential_client: classification.intent === 'new_client',
    sms_message: classification.suggested_response,
    requires_human_review: true,
    review_status: 'pending'
  }
}];
